13	type Item = { type: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	
17	const BLOCK_PREMIUM = 60;
18	
19	const basePremiumFor = (items: Item[]): number => {
20	  if (items.length === 3 && items.every((i) => i.type === items[0].type)) {
21	    return BLOCK_PREMIUM;
22	  }
23	  return items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
24	};
25	
26	const premiumFor = (items: Item[]): number => {
27	  const basePremium = basePremiumFor(items);
28	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
29	  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
30	};
31	
32	type QuoteResult = { premium: number };
33	type ScenarioOutput = { results: QuoteResult[] };
34	
35	const quoteStep = ({ items }: Step): QuoteResult => ({
36	  premium: premiumFor(items),
37	});
38	
39	export const runScenario = (input: Scenario): ScenarioOutput => ({
40	  results: input.steps.map(quoteStep),
41	});
