const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const isBlockOfSameType = (items: Item[]): boolean =>
  items.length === BLOCK_SIZE && items.every((i) => i.type === items[0].type);

const sumOfBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);

const basePremiumFor = (items: Item[]): number =>
  isBlockOfSameType(items) ? BLOCK_PREMIUM : sumOfBasePremiums(items);
